#include <cuda_runtime.h>

#include <cstdio>
#include <iostream>
#include <iomanip>
#include <cmath>
#include <limits>
#include <chrono>
#include <cstdlib>

#define N 2048
#define IDX(i, j) ((i) + (j) * N)

static void initialize_data(float* f) {
  const float pi = acosf(-1.0f);
  for (int j = 0; j < N; ++j) {
    for (int i = 0; i < N; ++i) {
      if (i == 0 || i == N - 1) {
        f[IDX(i, j)] = sinf(j * 2.0f * pi / (N - 1));
      } else if (j == 0 || j == N - 1) {
        f[IDX(i, j)] = sinf(i * 2.0f * pi / (N - 1));
      } else {
        f[IDX(i, j)] = 0.0f;
      }
    }
  }
}

__global__ void jacobi_step_reduce(const float* __restrict__ f_old,
                                   float* __restrict__ f,
                                   float* __restrict__ error) {
  __shared__ float sdata[256];

  const int tid = threadIdx.x;
  const int interior = N - 2;
  const int total = interior * interior;
  const int stride = blockDim.x * gridDim.x;
  int idx = blockIdx.x * blockDim.x + tid;

  float local_sum = 0.0f;

  while (idx < total) {
    const int i = (idx % interior) + 1;
    const int j = (idx / interior) + 1;
    const int center = IDX(i, j);

    float t = 0.25f * (f_old[center - 1] +
                       f_old[center + 1] +
                       f_old[center - N] +
                       f_old[center + N]);
    float df = t - f_old[center];
    f[center] = t;
    local_sum += df * df;

    idx += stride;
  }

  sdata[tid] = local_sum;
  __syncthreads();

  for (int offset = blockDim.x / 2; offset > 0; offset >>= 1) {
    if (tid < offset) {
      sdata[tid] += sdata[tid + offset];
    }
    __syncthreads();
  }

  if (tid == 0) {
    atomicAdd(error, sdata[0]);
  }
}

int main() {
  auto start_time = std::chrono::steady_clock::now();

  float* f = (float*)malloc(N * N * sizeof(float));
  float* f_old = (float*)malloc(N * N * sizeof(float));

  float error = {std::numeric_limits<float>::max()};
  const float tolerance = 1.e-5f;

  initialize_data(f);
  initialize_data(f_old);

  const int max_iters = 10000;
  int num_iters = 0;

  float* d_f = nullptr;
  float* d_f_old = nullptr;
  float* d_error = nullptr;

  cudaMalloc((void**)&d_f, N * N * sizeof(float));
  cudaMalloc((void**)&d_f_old, N * N * sizeof(float));
  cudaMalloc((void**)&d_error, sizeof(float));

  cudaMemcpy(d_f, f, N * N * sizeof(float), cudaMemcpyHostToDevice);
  cudaMemcpy(d_f_old, f_old, N * N * sizeof(float), cudaMemcpyHostToDevice);

  auto start = std::chrono::steady_clock::now();

  const int threads = 256;
  const int total_points = (N - 2) * (N - 2);
  int blocks = (total_points + threads - 1) / threads;
  if (blocks > 65535) blocks = 65535;

  while (error > tolerance && num_iters < max_iters) {
    error = 0.0f;
    cudaMemset(d_error, 0, sizeof(float));

    jacobi_step_reduce<<<blocks, threads>>>(d_f_old, d_f, d_error);
    cudaMemcpy(&error, d_error, sizeof(float), cudaMemcpyDeviceToHost);

    error = sqrtf(error / (N * N));

    if (num_iters % 1000 == 0) {
      std::cout << "Error after iteration " << num_iters << " = " << error << std::endl;
    }

    float* tmp = d_f_old;
    d_f_old = d_f;
    d_f = tmp;

    ++num_iters;
  }

  auto end = std::chrono::steady_clock::now();
  auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
  std::cout << "Average execution time per iteration: " << (time * 1e-9f) / num_iters << " (s)\n";

  if (error <= tolerance && num_iters < max_iters) {
    std::cout << "PASS" << std::endl;
  } else {
    std::cout << "FAIL" << std::endl;
    cudaFree(d_f);
    cudaFree(d_f_old);
    cudaFree(d_error);
    free(f);
    free(f_old);
    return -1;
  }

  cudaFree(d_f);
  cudaFree(d_f_old);
  cudaFree(d_error);

  free(f);
  free(f_old);

  auto end_time = std::chrono::steady_clock::now();
  auto total_time = std::chrono::duration_cast<std::chrono::nanoseconds>(end_time - start_time).count();
  double duration = total_time * 1e-9;
  std::cout << "Total elapsed time: " << std::setprecision(4) << duration << " seconds" << std::endl;

  return 0;
}
